class Solution {
    public boolean isPossible(int[] nums) {
        int count1 = 0, count2 = 0, count3 = 0;
        int prev = nums[0], curr = 1;
        for (int i = 1; i < nums.length; i++) {
            if (nums[i] == prev) {
                curr++;
            } else if (nums[i] == prev + 1) {
                if (curr >= 3) {
                    count1++;
                } else {
                    count2 = curr;
                    count3 = 0;
                }
                prev = nums[i];
                curr = 1;
            } else {
                if (count2 > 0) {
                    count1 += count2 / 3;
                    count2 %= 3;
                }
                if (count2 + count3 > 0) {
                    return false;
                }
                count1++;
                prev = nums[i];
                curr = 1;
            }
        }
        if (curr >= 3) {
            count1++;
        } else {
            count2 = curr;
        }
        if (count2 > 0) {
            count1 += count2 / 3;
            count2 %= 3;
        }
        return count2 == 0;
    }
}
